+        label: "Allow Once",
+        command: "/approve req-surrogate-terminal-proof allow-once",
+        style: "success",
+      },
+    ],
+  },
+} as never);
+
+const commandMrkdwn = readMrkdwnTexts((payload as { blocks?: unknown }).blocks).find((entry) =>
+  entry.startsWith("*Command*"),
+);
+
+if (!commandMrkdwn) {
+  throw new Error("Expected command mrkdwn block");
+}
+
